// 1. Gelen veriyi güvenli bir şekilde al
const inputItem = $input.first();
const inputBody = inputItem ? inputItem.json.body : {};

let parsedBody = inputBody;

// 2. 'no-cors' modunda veri string gelirse JSON'a çevir
if (typeof inputBody === 'string') {
    try {
        parsedBody = JSON.parse(inputBody);
    } catch (e) {
        console.log("JSON Parse Hatası:", e);
        parsedBody = {}; 
    }
}

// parsedBody null veya undefined ise boş obje yap (Hata Önleyici)
if (!parsedBody) {
    parsedBody = {};
}

let data = {};

// 3. Veri Kaynağını Ayırt Et
// A) TALLY FORMU
if (parsedBody.data && Array.isArray(parsedBody.data.fields)) {
    parsedBody.data.fields.forEach(field => {
        if (field.label) {
            data[field.label] = field.value;
        }
    });
} 
// B) FİŞMATİK PANELİ
else {
    data = parsedBody;
}

// 4. Telefon Numarası Formatlama
const normalizePhone = (phone) => {
    if (!phone) return "";
    let clean = phone.toString().replace(/\D/g, ''); 
    if (clean.startsWith('0')) clean = clean.substring(1);
    if (clean.startsWith('90') && clean.length > 10) clean = clean.substring(2);
    if (clean.length === 10) return "+90" + clean;
    return "+" + clean;
};

// 5. Çıktı (Mapping) - data[...] erişimlerinde hata vermez
return {
    json: {
        telegram_id: data['telegram_id'] || "", 

        // İsimlendirme farklarını yönet (Tally vs Panel)
        first_name: data['Adınız'] || data['first_name'] || "",
        last_name: data['Soyadınız'] || data['last_name'] || "",
        email: data['Mail Adresiniz'] || data['email'] || "",

        phone: normalizePhone(data['Telefon Numaranız'] || data['phone']),

        company_name: data['Şirketiniz'] || data['company_name'] || "",
        tax_office: data['Vergi Dairesi'] || data['tax_office'] || "",
        tax_no: data['Vergi Numarası'] || data['tax_no'] || "",

        password: data['password'] || Math.random().toString(36).slice(-8),

        source: parsedBody.data ? 'Tally Form' : 'FişMatik Panel'
    }
};

// 1. ADIM: Şirket ID'sini al (Önceki Supabase düğümünden)
const companyId = $input.first().json.id;

// 2. ADIM: Form verisini al ('form verilerini temizle' düğümünden)
// Artık veriler standart formatta (first_name, last_name vb.) geliyor.
const formData = $('form verilerini temizle').first().json; 

const usersList = [];

// A) YÖNETİCİYİ EKLE (Formu Dolduran)
const ad = formData.first_name || "";
const soyad = formData.last_name || "";
const tel = formData.phone;
const mail = formData.email;

// Yöneticiyi listeye ekle
// (Telefon veya Mail varsa geçerli sayıyoruz)
if (tel || mail) {
    usersList.push({
        company_id: companyId,
        full_name: `${ad} ${soyad}`.trim(), 
        phone_number: tel,
        email: mail, 
        telegram_id: formData.telegram_id || null,
        role: 'admin',
        // Şifreyi de taşıyalım, sonraki auth adımında lazım olabilir
        password: formData.password 
    });
}

// B) EK PERSONELLERİ EKLE (Opsiyonel - Tally Uyumluluğu)
// Eğer formData içinde 'personals' dizisi varsa işle, yoksa pas geç.
// (Şu anki parser kodu personals'ı geçirmiyor olabilir, bu blok hata vermeden atlar)
if (formData.personals && Array.isArray(formData.personals)) {
    formData.personals.forEach(p => {
        // --- GÜVENLİK FİLTRESİ ---
        if (p.adSoyad && p.telefon) {
            usersList.push({
                company_id: companyId,
                full_name: p.adSoyad,
                phone_number: p.telefon,
                email: null, // Personel maili yoksa null
                telegram_id: null,
                role: p.rol === 'Yönetici' ? 'admin' : 'user',
                // Personel için geçici rastgele şifre (Auth kaydı yapılacaksa)
                password: Math.random().toString(36).slice(-8)
            });
        }
    });
}

// C) SON FİLTRE (Boş isimleri temizle)
const finalCleanList = usersList.filter(user => 
    user.full_name && user.full_name.trim() !== ""
);

// n8n formatında çıktı ver
return finalCleanList.map(u => ({ json: u }));

